snapshot.eval/tests/unit/question-selection/negat:
{
  "input": {
    "scenario": "mid-research-flynn",
    "user_message": "Find a 1860 census record for Patrick Flynn."
  },
  "judge_context": [
    "Should route to search-records rather than wrap the request in a new research question"
  ],
  "negative": {
    "correct_skill": [
      "search-records"
    ],
    "explanation": "The user has named the record they want (1860 census, Patrick Flynn). That is a search task. question-selection proposes the research *question* — the framing of what to ask — not the specific record-fetch that answers it. A search request bypasses question-selection entirely and goes straight to search-records."
  },
  "test": {
    "id": "ut_question_selection_004",
    "skill": "question-selection",
    "type": "negative"
  }
}

snapshot.eval/tests/unit/question-selection/next-:
{
  "input": {
    "scenario": "mid-research-flynn",
    "user_message": "What should I research next?"
  },
  "judge_context": [
    "Should recognize that pli_006 (probate search for Thomas Flynn 1870-1890) is still in_progress and that the in-flight plan should be completed before introducing new questions",
    "If the skill does recommend a follow-up question, it should be one that depends on the probate result (e.g., a sibling-identification question that follows from a will naming children) and explicitly mark `depends_on: [\"q_001\"]`",
    "Should reference the specific plan item (`pli_006`) by ID — not just 'the probate search' — so the recommendation is anchored in research.json state"
  ],
  "test": {
    "id": "ut_question_selection_001",
    "skill": "question-selection",
    "type": "positive"
  }
}

snapshot.eval/tests/unit/question-selection/prior:
{
  "input": {
    "scenario": "flynn-multi-conflict",
    "user_message": "What should I research next given the current state of the project?"
  },
  "judge_context": [
    "Should recognize that q_001 is blocked by unresolved conflicts c_001 and c_002",
    "The proposed question should target evidence that would distinguish the competing assertions — for c_001 (birthplace) that might be a marriage record or naturalization papers; for c_002 (identity) it might be a later census or vital record that anchors the subject's identity"
  ],
  "test": {
    "id": "ut_question_selection_003",
    "skill": "question-selection",
    "type": "positive"
  }
}

